import{_ as e,o as r,c as t,a2 as o}from"./chunks/framework.DdiKTz4X.js";const f=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1783403905000}'),d={name:"guide/faq.md"};function i(l,a,n,h,c,s){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="怎么最快找到资料" tabindex="-1">怎么最快找到资料？ <a class="header-anchor" href="#怎么最快找到资料" aria-label="Permalink to &quot;怎么最快找到资料？&quot;">​</a></h2><p>先进入 <a href="/free-knowledge-base/library/">资料库</a> 按分类浏览。如果知道关键词，可以直接使用顶部搜索框。</p><h2 id="为什么某个分类显示-暂无资料" tabindex="-1">为什么某个分类显示“暂无资料”？ <a class="header-anchor" href="#为什么某个分类显示-暂无资料" aria-label="Permalink to &quot;为什么某个分类显示“暂无资料”？&quot;">​</a></h2><p>这表示当前知识库还没有收录该分类的公开资料。后续补充后，资料会自动出现在对应分类下。</p><h2 id="pdf-可以在线查看吗" tabindex="-1">PDF 可以在线查看吗？ <a class="header-anchor" href="#pdf-可以在线查看吗" aria-label="Permalink to &quot;PDF 可以在线查看吗？&quot;">​</a></h2><p>可以。PDF 资料会有单独页面，可以在浏览器中预览，也可以打开或下载原文件。</p><h2 id="word-文档可以看吗" tabindex="-1">Word 文档可以看吗？ <a class="header-anchor" href="#word-文档可以看吗" aria-label="Permalink to &quot;Word 文档可以看吗？&quot;">​</a></h2><p>如果资料是 <code>.docx</code>，网站会尽量转换为网页内容，并提供原文件下载链接。旧版 <code>.doc</code> 通常以下载方式提供。</p><h2 id="搜索不到想要的内容怎么办" tabindex="-1">搜索不到想要的内容怎么办？ <a class="header-anchor" href="#搜索不到想要的内容怎么办" aria-label="Permalink to &quot;搜索不到想要的内容怎么办？&quot;">​</a></h2><p>可以尝试更短的关键词，例如把“STM32 GPIO 初始化”改成“GPIO”或“STM32”。如果仍然没有结果，说明当前知识库暂未收录。</p>',11)])])}const _=e(d,[["render",i]]);export{f as __pageData,_ as default};
